Code.Terraform:
```hcl
# OpenSearch Dashboards のために Amazon Cognito 認証を有効にする
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cognito_options {
    enabled          = true  # 重要: Dashboards のチェックを通過するために Cognito 認証を有効にする
    user_pool_id     = "<USER_POOL_ID>"
    identity_pool_id = "<IDENTITY_POOL_ID>"
    role_arn         = "<ROLE_ARN>"
  }
}
```
